import{_ as t,c as e,o as i,a1 as l}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Быстрый старт: Установка и настройка Antigravity Auth | OpenCode","description":"Изучите методы установки и настройки плагина Antigravity Auth. Завершите аутентификацию Google OAuth за 10 минут, отправьте первый запрос к модели и проверьте успешность доступа к моделям Claude и Gemini.","frontmatter":{"title":"Быстрый старт: Установка и настройка Antigravity Auth | OpenCode","sidebarTitle":"Запуск за 10 минут","subtitle":"Быстрый старт: Установка и настройка Antigravity Auth","description":"Изучите методы установки и настройки плагина Antigravity Auth. Завершите аутентификацию Google OAuth за 10 минут, отправьте первый запрос к модели и проверьте успешность доступа к моделям Claude и Gemini.","order":1},"headers":[],"relativePath":"ru/NoeFabris/opencode-antigravity-auth/start/index.md","filePath":"ru/NoeFabris/opencode-antigravity-auth/start/index.md"}'),r={name:"ru/NoeFabris/opencode-antigravity-auth/start/index.md"};function o(n,a,h,u,s,d){return i(),e("div",null,[...a[0]||(a[0]=[l('<h1 id="быстрыи-старт" tabindex="-1">Быстрый старт <a class="header-anchor" href="#быстрыи-старт" aria-label="Permalink to &quot;Быстрый старт&quot;">​</a></h1><p>Эта глава поможет вам начать использование плагина Antigravity Auth с нуля. Вы узнаете о ключевой ценности плагина, завершите установку и аутентификацию OAuth, а также отправите первый запрос к модели для проверки успешности настройки.</p><h2 id="путь-обучения" tabindex="-1">Путь обучения <a class="header-anchor" href="#путь-обучения" aria-label="Permalink to &quot;Путь обучения&quot;">​</a></h2><p>Изучайте материалы в следующем порядке — каждый шаг основывается на предыдущем:</p><h3 id="_1-введение-в-плагин" tabindex="-1">1. <a href="./what-is-antigravity-auth/">Введение в плагин</a> <a class="header-anchor" href="#_1-введение-в-плагин" aria-label="Permalink to &quot;1. [Введение в плагин](./what-is-antigravity-auth/)&quot;">​</a></h3><p>Узнайте о ключевой ценности плагина Antigravity Auth, применимых сценариях и предупреждениях о рисках.</p><ul><li>Определите, подходит ли плагин для вашего сценария использования</li><li>Узнайте о поддерживаемых моделях ИИ (Claude Opus 4.5, Sonnet 4.5, Gemini 3 Pro/Flash)</li><li>Выясните риски использования и меры предосторожности</li></ul><h3 id="_2-быстрая-установка" tabindex="-1">2. <a href="./quick-install/">Быстрая установка</a> <a class="header-anchor" href="#_2-быстрая-установка" aria-label="Permalink to &quot;2. [Быстрая установка](./quick-install/)&quot;">​</a></h3><p>Установите плагин и завершите первую аутентификацию за 5 минут.</p><ul><li>Два способа установки (с ИИ-помощью / ручная настройка)</li><li>Настройка определений моделей</li><li>Выполнение аутентификации Google OAuth</li></ul><h3 id="_3-аутентификация-oauth-2-0-pkce" tabindex="-1">3. <a href="./first-auth-login/">Аутентификация OAuth 2.0 PKCE</a> <a class="header-anchor" href="#_3-аутентификация-oauth-2-0-pkce" aria-label="Permalink to &quot;3. [Аутентификация OAuth 2.0 PKCE](./first-auth-login/)&quot;">​</a></h3><p>Поймите процесс аутентификации OAuth 2.0 PKCE и завершите первый вход.</p><ul><li>Поймите механизм безопасности аутентификации PKCE</li><li>Завершите первый вход и получите доступ к API</li><li>Узнайте об автоматическом обновлении токенов</li></ul><h3 id="_4-первыи-запрос" tabindex="-1">4. <a href="./first-request/">Первый запрос</a> <a class="header-anchor" href="#_4-первыи-запрос" aria-label="Permalink to &quot;4. [Первый запрос](./first-request/)&quot;">​</a></h3><p>Отправьте первый запрос к модели и проверьте успешность установки.</p><ul><li>Отправьте первый запрос к модели Antigravity</li><li>Поймите параметры <code>--model</code> и <code>--variant</code></li><li>Устраните распространённые ошибки запросов к моделям</li></ul><h2 id="предварительные-условия" tabindex="-1">Предварительные условия <a class="header-anchor" href="#предварительные-условия" aria-label="Permalink to &quot;Предварительные условия&quot;">​</a></h2><p>Перед началом этой главы убедитесь:</p><ul><li>✅ Установлен OpenCode CLI (команда <code>opencode</code> доступна)</li><li>✅ Имеется учётная запись Google (для аутентификации OAuth)</li></ul><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения быстрого старта вы можете:</p><ul><li><strong><a href="./../platforms/available-models/">Доступные модели</a></strong> — исследовать все поддерживаемые модели и их конфигурации вариантов</li><li><strong><a href="./../advanced/multi-account-setup/">Настройка нескольких аккаунтов</a></strong> — настроить несколько учётных записей Google для объединения квот</li><li><strong><a href="./../faq/common-auth-issues/">Распространённые проблемы аутентификации</a></strong> — обратиться к руководству по устранению неполадок при возникновении проблем</li></ul>',22)])])}const f=t(r,[["render",o]]);export{p as __pageData,f as default};
